import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"24. Part Time Employment","description":"","frontmatter":{"title":"24. Part Time Employment","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","employment","classifications"]},"headers":[],"relativePath":"ebas/mspp/employment/24-part-time-employment.md","filePath":"ebas/mspp/employment/24-part-time-employment.md"}'),n={name:"ebas/mspp/employment/24-part-time-employment.md"};function s(i,e,p,l,m,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_24-part-time-employment" tabindex="-1">24. Part Time Employment <a class="header-anchor" href="#_24-part-time-employment" aria-label="Permalink to &quot;24. Part Time Employment&quot;">​</a></h1><p>An Employer may employ part-time Employees in any classification in this Agreement. A regular part-time Employee is a person who:</p><p><strong>a.</strong> works less than full-time hours of 38 per week (or less than 76 hours in a fortnight); and</p><p><strong>b.</strong> has reasonably predictable hours of work; and</p><p><strong>c.</strong> receives, on a pro rata basis, equivalent pay and conditions to those for full- time Employees who do the same kind of work.</p><p><strong>24.2</strong> Minimum Engagement The minimum period of engagement of a part time Employee is three (3) hours per day</p><p><strong>a.</strong> At the time of engagement, the Employer and the part-time Employee will agree in writing on the following matters:</p><p><strong>(i)</strong> a regular pattern of work, specifying the hours worked each day;</p><p><strong>(ii)</strong> which days of the week the Employee will work; and</p><p><strong>(iii)</strong> the actual starting and finishing times each day.</p><p><strong>b.</strong> Any agreed variation to the regular pattern of work will be recorded in writing.</p><p><strong>c.</strong> Part-time Employees shall be paid:</p><p><strong>(i)</strong> for all Employees except Pharmacists at an hourly rate equal to 1/38th of the weekly rate appropriate to the Employee&#39;s classification; Employees employed under this clause shall receive leave entitlements on a pro rata basis.</p><p><strong>(ii)</strong> the conditions of part-time work shall be agreed upon between Employer and Employee and shall be confirmed in writing between the two parties.</p><p><strong>d.</strong> For Pharmacists per hour worked at an amount equal to 1/38th of the weekly rate appropriate to the Employee’s classification, and payment in respect of any Annual Leave or Long Service leave to which an Employee may become entitled shall be on a pro rata basis. Payment in respect of any period of paid Personal Leave (where an Employee has accumulated an entitlement) shall be</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>made according to the number of hours the Employee would have worked on the day or days on which the leave was taken so as not to reduce the Employee’s wage below that level which such Employee would have received had such Employee not been absent.</p><p>Plain language terms: part-time, PT.</p>',18)])])}const y=t(n,[["render",s]]);export{d as __pageData,y as default};
